import React, { Component } from 'react';
import Button from '../components/Button';
import FormGroup from '../components/FormGroup';

class Infobase extends Component {

  constructor(props) {
    super(props);

    const categories = [
        { id: 1, pagetitle: "выберите категорию 1" },
        { id: 2, pagetitle: "выберите категорию 2" },
        { id: 3, pagetitle: "выберите категорию 3" },
        { id: 4, pagetitle: "выберите категорию 4" },
      ],
      items = [
        { parent: 1, pagetitle: "IBM Radar", longtitle: "0325474", description: "В данном каталоге Вы можете выбрать все интересующие Вас направления и продукты. Для того чтобы получить подробную информацию, отметьте все необходимые продукты и нажмите кнопку «рассчитать», мы вышлем Вам всю информацию в кратчайшие сроки. можете выбрать все интересующие", document: "/assets/document/1.pdf" },
        { parent: 1, pagetitle: "IBM Radar", longtitle: "0325474", description: "В данном каталоге Вы можете выбрать все интересующие Вас направления и продукты. Для того чтобы получить подробную информацию, отметьте все необходимые продукты и нажмите кнопку «рассчитать», мы вышлем Вам всю информацию в кратчайшие сроки. можете выбрать все интересующие", document: "/assets/document/1.pdf" },
        { parent: 1, pagetitle: "Microsoft Azure", longtitle: "0325474", description: "В данном каталоге Вы можете выбрать все интересующие Вас направления и продукты. Для того чтобы получить подробную информацию, отметьте все необходимые продукты и нажмите кнопку «рассчитать», мы вышлем Вам всю информацию в кратчайшие сроки. можете выбрать все интересующие", document: "/assets/document/1.pdf" },
        { parent: 1, pagetitle: "IBM Radar", longtitle: "0325474", description: "В данном каталоге Вы можете выбрать все интересующие Вас направления и продукты. Для того чтобы получить подробную информацию, отметьте все необходимые продукты и нажмите кнопку «рассчитать», мы вышлем Вам всю информацию в кратчайшие сроки. можете выбрать все интересующие", document: "/assets/document/1.pdf" },
        { parent: 2, pagetitle: "Microsoft Azure", longtitle: "0325474", description: "В данном каталоге Вы можете выбрать все интересующие Вас направления и продукты. Для того чтобы получить подробную информацию, отметьте все необходимые продукты и нажмите кнопку «рассчитать», мы вышлем Вам всю информацию в кратчайшие сроки. можете выбрать все интересующие", document: "/assets/document/1.pdf" },
        { parent: 2, pagetitle: "IBM Radar", longtitle: "0325474", description: "В данном каталоге Вы можете выбрать все интересующие Вас направления и продукты. Для того чтобы получить подробную информацию, отметьте все необходимые продукты и нажмите кнопку «рассчитать», мы вышлем Вам всю информацию в кратчайшие сроки. можете выбрать все интересующие", document: "/assets/document/1.pdf" },
        { parent: 3, pagetitle: "IBM Radar", longtitle: "0325474", description: "В данном каталоге Вы можете выбрать все интересующие Вас направления и продукты. Для того чтобы получить подробную информацию, отметьте все необходимые продукты и нажмите кнопку «рассчитать», мы вышлем Вам всю информацию в кратчайшие сроки. можете выбрать все интересующие", document: "/assets/document/1.pdf" },
        { parent: 4, pagetitle: "Microsoft Azure", longtitle: "0325474", description: "В данном каталоге Вы можете выбрать все интересующие Вас направления и продукты. Для того чтобы получить подробную информацию, отметьте все необходимые продукты и нажмите кнопку «рассчитать», мы вышлем Вам всю информацию в кратчайшие сроки. можете выбрать все интересующие", document: "/assets/document/1.pdf" },
        { parent: 4, pagetitle: "IBM Radar", longtitle: "0325474", description: "В данном каталоге Вы можете выбрать все интересующие Вас направления и продукты. Для того чтобы получить подробную информацию, отметьте все необходимые продукты и нажмите кнопку «рассчитать», мы вышлем Вам всю информацию в кратчайшие сроки. можете выбрать все интересующие", document: "/assets/document/1.pdf" },
        { parent: 4, pagetitle: "Intel", longtitle: "0325474", description: "В данном каталоге Вы можете выбрать все интересующие Вас направления и продукты. Для того чтобы получить подробную информацию, отметьте все необходимые продукты и нажмите кнопку «рассчитать», мы вышлем Вам всю информацию в кратчайшие сроки. можете выбрать все интересующие", document: "/assets/document/1.pdf" },
        { parent: 4, pagetitle: "IBM Radar", longtitle: "0325474", description: "В данном каталоге Вы можете выбрать все интересующие Вас направления и продукты. Для того чтобы получить подробную информацию, отметьте все необходимые продукты и нажмите кнопку «рассчитать», мы вышлем Вам всю информацию в кратчайшие сроки. можете выбрать все интересующие", document: "/assets/document/1.pdf" },
      ],
      categoryNames = [],
      productNames = [];
    
    categories.forEach(v => {
      categoryNames.push({ title: v.pagetitle, value: v.id });
    });
    
    items.forEach(v => {
      const vn = v.pagetitle;
      if( productNames.indexOf(vn) === -1 )
        productNames.push(vn);
    });
    
    this.state = {

      filters: {
        product: '',
        category: '',
      },

      categoryNames: categoryNames,
      productNames: productNames,
      
      page: {
        pagetitle: "Бзаа знаний",
        categories: categories,
        items: items,
      }
    }
  }
  
  handleChange = (v) => {
    this.setState({
      filters: Object.assign( this.state.filters, { [v.name]: v.value })
    });
  }

  handleSubmit(e) {
    e.preventDefault();
    console.log(this.state)
  }
  
  render() {

    const page = this.state.page,
      filters = this.state.filters,
      categoryNames = this.state.categoryNames,
      productNames = this.state.productNames,
      formSettings = {
        type: 'select',
        handleChange: e => this.handleChange(e),
      };

    return (
      <div className="page-infobase">
        <header className="main__header">
        
          <h1 className="main__title">{page.pagetitle}</h1>
          
          <form className="filters" onSubmit={ e => this.handleSubmit(e) }>

            <FormGroup placeholder="выберите продукт" name="product" value={filters.product.title} values={productNames} {...formSettings}/>
            <FormGroup placeholder="выберите вашу версию" name="category" value={filters.category.title} values={categoryNames} {...formSettings}/>

            <Button class="hide"/>
          </form>
        </header>

        <section className="table__container">
          <div className="table">
            <header>
              <ul>
                <li className="table__title">Продукт</li>
                <li className="table__longtitle">Версия</li>
                <li className="table__description">Краткое описание</li>
              </ul>
            </header>
            
            <ul>
              {page.items.map( (v,i) => {

                if(
                  ( filters.product.value && filters.product.value !== v.pagetitle )
                  || ( filters.category.value && filters.category.value !== v.parent )
                  )
                  return '';
                
                return (
                  <li key={i}>
                    <h3 className="table__title">{v.pagetitle}</h3>
                    <p className="table__longtitle">{v.longtitle}</p>
                    <p className="table__description">{v.description}</p>
                    <p className="table__link">
                      <a href={'/'+v.document} target="_blank">
                        <i className="ico_arrow ico_arrow_success ico_arrow_small ico_arrow_middle"></i>
                        <span>сказать</span>
                      </a>
                    </p>
                  </li>
                )
              })}
            </ul>
          </div>
        </section>
      </div>
    );
  }
}
export default Infobase;



