import React, { Component } from 'react';
import Button from '../components/Button';
import server from '../server';
import Modal from 'react-modal';

class Home extends Component {

  state = {
    page: {},
    product: false,
  }
  
  constructor(props) {
    super(props);
    this.getData();
  }

  getData() {

    // this.props.handleLoading(true);
    
    fetch(server.uri+'page/catalog', server.params)
      .then(response => response.json())
      .then(data => {
        this.setState({ page: data })
        // this.props.handleLoading(false);
  });
  }
  getProduct(uri) {

    this.setState({ product: 'loading' });
    
    fetch(server.uri+'page/'+uri, server.params)
      .then(response => response.json())
      .then(data => {
        this.setState({ product: data })
      });
  }
  
  handleToggleCatalog = id => {

    var items = this.state.page.items,
      idx = -1;

    items.forEach((v,i) => {
      if( v.id === id )
        idx = i;
    });
    
    if( idx === -1 ) return 0;
    
    items[idx].active = !items[idx].active;
    this.setState({
      page: Object.assign(this.state.page, { items: items })
    });
  }
  handleModalClose = () => {
    this.setState({ product: false });
  }
  
  renderItem(item) {

    const css = "catalog__item";
    
    return (
      <div className={css+( item.active ? ' active' : '' )+( item.items && item.items.length ? ' childs_exist' : '' )}>

        <div className={css+'__title'}>
          <Button theme="text" handleClick={ () => this.handleToggleCatalog(item.id) }>
            <i className="catalog__item__icon"></i>
            { item.pagetitle }
          </Button>
        </div>

        <ul className={css+'__childs'} style={{ height: item.active ? ( ( item.items && item.items.length ? item.items.length : 1 ) * 34)+'px' : '0px' }}>
          {
            item.items && item.items.length
              ? item.items.map( (v,i) => <li key={i}>{ this.renderItemChild(v) }</li> )
              : <li className={css+'__undefined'}>продукты не найдены</li>
          }
        </ul>
      </div>
    );
  }

  renderItemChild(item) {

    const css = "catalog__item__child";
    
    return (
      <div className={css}>

        <h3 className={css+'__title'}>
          <i className="catalog__item__icon"></i>
          <span>{item.pagetitle}</span>
        </h3>

        <div className={css+'_btns'}>
          <Button theme="info" handleClick={() => this.getProduct(item.uri)}>подробнее...</Button>
          <Button theme="success">добавить в корзину</Button>
        </div>
      </div>
    );
  }
  
  render() {

    const page = this.state.page,
      product = this.state.product;
    
    return (
      <article className="page-catalog">
      
        <header className="main__header">
          <h1 className="main__title"><span>{page.pagetitle}</span></h1>
        </header>

        <section className="main__content" dangerouslySetInnerHTML={{ __html: page.content }}></section>

        { page.items ? <section className="catalog__items">
          <hr/>
          <ul>
            { page.items.map( (v,i) => (
              <li key={i}>{ this.renderItem(v) }</li>
            ))}
          </ul>
        </section> : '' } 

        <Modal className="modal__product" isOpen={product} onRequestClose={ () => this.handleModalClose() }>
          { product === 'loading'
            ? <div className="modal__laoding"></div>
            : <article>
              <header className="modal__header">

                <Button theme="remove" class="modal__close" handleClick={ () => this.handleModalClose() }></Button>
              
                <h2 className="page__title">
                  <span>{product.pagetitle}</span>
                </h2>
                <div className="table">
                  <ul>
                    <li valign="top">
                      <h3 className="table__title">{product.publishedon}</h3>
                      <p className="table__longtitle">{product.longtitle}</p>
                      <p className="table__description">{product.introtext}</p>
                      { product.document ? <p className="table__link">
                        <a href={'/'+product.document} target="_blank">
                          <i className="ico_arrow ico_arrow_success ico_arrow_small ico_arrow_middle"></i>
                          <span>{product.introtext}</span>
                        </a>
                      </p> : '' }
                    </li>
                  </ul>
                </div>
              </header>

              <section className="modal__body" dangerouslySetInnerHTML={{ __html: product.content }}></section>
            </article>
          }
        </Modal>
      </article>
    );
  }
}
export default Home;



