import React, { Component } from 'react';
import { BrowserRouter as Router, Route, Switch } from 'react-router-dom';
import Calendar from 'react-calendar';
import Header from './components/Header';
import './App.css';
import Button from './components/Button';
import FormGroup from './components/FormGroup';
import server from './server';
// pages
import Home from './pages/Home';
import Catalog from './pages/Catalog';
import Login from './pages/Login';
import Infobase from './pages/Infobase';
import Cabinet from './pages/Cabinet';

class App extends Component {

  state = {
    
    loading: false,
    user: localStorage.user && JSON.parse(localStorage.user),
    
    phone: "",
    phoneHref: "",
    phone2: "",
    phone2Href: "",
    address: "",
    basesite: "",
    
    emails: [],
    menu: [],
    asidemenu: [],
    asidemenuOpen: "",

    form: {
      message: "",
      email: "",
    },
    formLogin: {
      email: "",
      password: "",
      error: false,
    },

    card: {
      items: []
    }
  }

  constructor(props) {
    super(props);
    this.getData();
  }

  getData() {
    fetch(server.uri+'base', server.params)
      .then(response => response.json())
      .then(data => {
        this.setState({ ...data })
      });
  }
  
  handleFormChange = (e) => {

    const form = this.state.form,
      t = e.target;

    form[t.name] = t.value;
    
    this.setState({
      form: form
    });
  }
  
  handleAsideMenuToggle(v) {
    this.setState({
      asidemenu: Object.assign( this.state.asidemenu, { open: v } )
    });
  }
  handleLoading = (v) => {
    console.log(v);
    this.setState({ loading: v });
  }

  handleLoginChange = (e) => {
    const t = e.target;
    this.setState({
      formLogin: Object.assign(this.state.formLogin, { [t.name]: t.value })
    });
  }
  handleLoginSubmit = (e) => {

    e.preventDefault();

    const form = this.state.formLogin;

    if( form.email === 'test@asd.as' && form.password === 'qwerasdf' ){

      const v = {
        id: "072349756",
        name: "Андреев Сергей"
      };

      this.setState({ user: v});
      localStorage.setItem('user', JSON.stringify(v));
    }
    else {
      alert("Неверный логин или пароль");
      form.error = true;
      this.setState({ formLogin: form });
    }
  }
  handleSignout = () => {
    this.setState({ user: false });
    localStorage.removeItem('user');
  }
  
  renderAsideLeft() {

    const state = this.state;
    
    return (
      <aside className="page-aside aside_left">

        <header>
          <a className="logo_white" href="/">
            <img src="/assets/imgs/logo-white.svg" alt="ICORE ITAC"/>
          </a>
        </header>

        <section className="aside__menu">
          <ul>
            <li>
              <h3 className="aside__title">Информация о подписке</h3>
              <ul>
                { state.asidemenu && state.asidemenu.map( (v,i) => (
                  <li key={i}><a href={ '/'+v.uri }>{ v.menutitle ? v.menutitle : v.pagetitle }</a></li>
                ))}
              </ul>
            </li>
            <li>
              <a className="aside__title" href="">База знаний</a>
            </li>
          </ul>
        </section>

        <section className="callback">
          <form action="request/callback" method="POST">

            <input type="hidden" name="title" value="Левый блок: Обратная свзяь - задать вопрос"/>

            <h3 className="aside__title aside__title_green">Обратная связь</h3>
            
            <div className="form-group">
              <label htmlFor="callbackMessage" className={ this.state.form.message && 'hide' }>Задайте вопрос...</label>
              <textarea id="callbackMessage" name="message" placeholder="Задайте вопрос..." rows="10" onChange={ e => this.handleFormChange(e) }></textarea>
            </div>
            
            <div className="form-group callback__email">
              <input id="callbackEmail" type="email" name="email" className="form__input" placeholder="email"/>
            </div>
            
            <div className="callback__btns">
              <Button theme="success">Отправить</Button>
            </div>
          </form>
        </section>

        <section className="contacts">
          <h3 className="aside__title">Контакты</h3>
          <p className="aside__description">{ this.state.address }<br/><a href={`tel:${ this.state.phoneHref }`}>{ this.state.phone }</a></p>
        </section>

        <footer>
          <ul className="list_links">

            { this.state.emails.map( (v,i) => (
              <li key={i}><a href={`mailto:${v}`}>{v}</a></li>
            ))}

            <li><a href={ this.state.basesite }>{ this.state.basesite }</a></li>
          </ul>
        </footer>
      </aside>
    );
  }
  renderAsideRight() {

    const user = this.state.user,
      formLogin = this.state.formLogin,
      formLoginSettings = {
        required: true,
        handleChange: e => this.handleLoginChange(e),
      };
    
    return (
      <aside className="page-aside aside_right">

        <header>
          { !user
            ? <form className="login-form" onSubmit={ e => this.handleLoginSubmit(e) }>

              <img src="/assets/imgs/profile-picture.svg" alt="Profile avatar"/>

              <FormGroup type="email" name="email" value={formLogin.email} placeholder="email" {...formLoginSettings}/>
              <FormGroup type="password" name="password" value={formLogin.password} placeholder="пароль" {...formLoginSettings}/>

              <div className="loginform__btns">
                <Button theme="success">Войти</Button>
                <a href="login/forget">забыли пароль?</a>
              </div>
            </form>
            : <div className="profile">
            
              <img src="/assets/imgs/profile-picture.svg" alt="Profile avatar"/>

              <div className="profile__info">
                <p className="profile__name">{user.name}</p>
                <p className="profile__id">№{user.id}</p>
              </div>

              <div className="profile__btn">
                <Button theme="success" handleClick={ () => this.handleSignout() }>Выйти</Button>
              </div>
            </div>
          }
        </header>

        <section>
          <a className="aside__phone" href={`tel:${this.state.phone2Href}`}>{ this.state.phone2 }</a>
        </section>

        <section>
          <a className="aside__title aside__title_blue" href="portal">Перейти в портал</a>
        </section>

        <section className="aside__calendar">
          <Calendar locale="ru-RU" value={ new Date() }/>
        </section>

        <section className="callback">
          <form action="request/callback">

            <h3 className="aside__title aside__title_green">Оставить заявку</h3>

            <input type="hidden" name="title" value="Правй блок: Оставить заявку"/>

            <FormGroup class="aside__wrap" name="name" placeholder="Ф.И.О." handleChange={ this.handleFormChange }/>
            <FormGroup class="aside__wrap" name="position" placeholder="Должность" handleChange={ this.handleFormChange }/>
            <FormGroup class="aside__wrap" name="company" placeholder="Компания" handleChange={ this.handleFormChange }/>
            <FormGroup class="aside__wrap" name="email" type="email" placeholder="Email" handleChange={ this.handleFormChange }/>
            <FormGroup class="aside__wrap" name="phone" type="tel" placeholder="Контактный номер" handleChange={ this.handleFormChange }/>

            <div className="callback__btns">
              <Button theme="success">Отправить</Button>
            </div>
          </form>
        </section>

        <section>

          <h3 className="aside__title">Каталог / корзина запросов</h3>
          
          <div className="card_aside">
            <ul>
              { this.state.card.items.map( (v,i) => (
                <li key={i}>
                  <a href={ v.uri }>{ v.pagetitle }</a>
                  <Button theme="remove"></Button>
                </li>
              ))}
            </ul>
          </div>
        </section>

        <footer>
          <div className="card_aside__btn">
            <Button theme="success" disabled={ !this.state.card.items.length }>Рассчитать запрос</Button>
          </div>
        </footer>
      </aside>
    );
  }
  
  renderMain() {

    const routeSettings = {
      //   handleLoading: () => this.handleLoading
      },
      loginSettings = {
        form: this.state.formLogin,
        handleChange: e => this.handleLoginChange(e),
        handleSubmit: e => this.handleLoginSubmit(e),
      };
    
    return (
      <main>

        { this.state.loading ? <div className="loading"></div> : '' }
        
        <Router>
          <Switch>
            
            {/* home */}
            <Route exact path="/" render={ () => <Home {...routeSettings}/> }/>

            {/* Aboutus */}
            {/* <Route exact path="/aboutus" render={ () => <Aboutus handleModalToggle={ this.handleModalToggle }/> } /> */}

            {/* catalog */}
            <Route path="/catalog" component={ route => <Catalog route={route} {...routeSettings}/> }/>
            {/* <Route exact path="/catalog/:id"
              component={ route =>
                <CatalogItem route={ route }
                  handleCardGet={ this.handleCardGet }
                  handleModalToggle={ this.handleModalToggle }/>
              }
              /> */}

            {/* infobase */}
            <Route exact path="/infobase" render={ () => <Infobase {...routeSettings}/> }/>

            {/* login & cabinet */}
            { !this.state.user ? <Route path="/cabinet" render={ () => <Login {...loginSettings}/> } /> : '' }
            <Route path="/cabinet" component={ route => <Cabinet route={route} {...routeSettings}/> } />

            {/* contacts */}
            {/* <Route exact path="/contacts" component={ () => <Contacts /> } /> */}
            
            {/* <Route exact path="/card" component={ () => <PageCard card={ this.state.card }
              handleCardItemCountChange={ this.handleCardItemCountChange }
              handleCardItemRemove={ this.handleCardItemRemove }/> } /> */}
          </Switch>
        </Router>
      </main>
    );
  }
  
  render() {    
    return (
      <div className="App">

        <div className="app__bg img_bg" style={{ backgroundImage: `url('/assets/imgs/bg.jpg')` }}></div>
      
        <Header menu={ this.state.menu }/>

        <section className="page-body">
          <div className="container">
            { this.renderAsideLeft() }
            { this.renderMain() }
            { this.renderAsideRight() }
          </div>
        </section>

        <footer className="page-footer"></footer>
      </div>
    );
  }
}

export default App;



